diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 76020d2b1dbf..e374373755a6 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7461,12 +7461,27 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   if (Instruction *Res = canonicalizeICmpPredicate(I))
     return Res;

+
   if (Instruction *Res = foldICmpWithConstant(I))
     return Res;

   if (Instruction *Res = foldICmpWithDominatingICmp(I))
     return Res;

+  // icmp eq (trunc nuw X to i1), (trunc nuw Y to i1) -> icmp eq X, Y
+  // icmp ne (trunc nuw X to i1), (trunc nuw Y to i1) -> icmp ne X, Y
+  if (ICmpInst::isEquality(I.getPredicate()) && match(Op0, m_Trunc(m_Value())) &&
+      match(Op1, m_Trunc(m_Value()))) {
+    auto *Trunc0 = cast<TruncInst>(Op0);
+    auto *Trunc1 = cast<TruncInst>(Op1);
+    if (Trunc0->hasNoUnsignedWrap() && Trunc1->hasNoUnsignedWrap() &&
+        Trunc0->getDestTy()->isIntegerTy(1) &&
+        Trunc1->getDestTy()->isIntegerTy(1) &&
+        Trunc0->getSrcTy() == Trunc1->getSrcTy()) {
+      return new ICmpInst(I.getPredicate(), Trunc0->getOperand(0), Trunc1->getOperand(0));
+    }
+  }
+
   if (Instruction *Res = foldICmpUsingBoolRange(I))
     return Res;

@@ -7489,6 +7504,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
     if (SelectInst *SI = dyn_cast<SelectInst>(I.user_back())) {
       Value *A, *B;
       SelectPatternResult SPR = matchSelectPattern(SI, A, B);
+
       if (SPR.Flavor != SPF_UNKNOWN)
         return nullptr;
     }

